UPDATE lessons SET content = '# Funções em JavaScript

Funções são blocos de código reutilizáveis que executam uma tarefa específica. São fundamentais para organizar e estruturar programas.

## Declaração de Função

### Função Tradicional
```javascript
function saudacao(nome) {
    return `Olá, ${nome}!`;
}

console.log(saudacao(''João''));  // "Olá, João!"
```

### Function Expression
```javascript
const saudacao = function(nome) {
    return `Olá, ${nome}!`;
};

console.log(saudacao(''Maria''));
```

### Arrow Function (ES6+)
```javascript
const saudacao = (nome) => {
    return `Olá, ${nome}!`;
};

// Versão curta (uma linha)
const saudacao = nome => `Olá, ${nome}!`;

// Sem parâmetros
const digaOi = () => ''Oi!'';

// Múltiplos parâmetros
const soma = (a, b) => a + b;
```

## Parâmetros

### Parâmetros Padrão
```javascript
function saudacao(nome = ''visitante'') {
    return `Olá, ${nome}!`;
}

console.log(saudacao());  // "Olá, visitante!"
console.log(saudacao(''João''));  // "Olá, João!"
```

### Rest Parameters
```javascript
function soma(...numeros) {
    return numeros.reduce((total, num) => total + num, 0);
}

console.log(soma(1, 2, 3));  // 6
console.log(soma(1, 2, 3, 4, 5));  // 15
```

### Destructuring
```javascript
function exibirPessoa({nome, idade}) {
    console.log(`${nome} tem ${idade} anos`);
}

exibirPessoa({nome: ''João'', idade: 25});
```

## Return

```javascript
function soma(a, b) {
    return a + b;
    console.log(''Nunca executa'');  // Código após return é ignorado
}

// Função sem return retorna undefined
function semRetorno() {
    console.log(''Olá'');
}
console.log(semRetorno());  // undefined
```

## Escopo

### Escopo Global
```javascript
let global = ''Acessível em todo lugar'';

function teste() {
    console.log(global);  // OK
}
```

### Escopo Local
```javascript
function teste() {
    let local = ''Só existe aqui'';
    console.log(local);  // OK
}

// console.log(local);  // ERRO!
```

### Escopo de Bloco
```javascript
if (true) {
    let blocoVar = ''Só existe no if'';
    const outra = ''Também'';
}

// console.log(blocoVar);  // ERRO!
```

## Closures

```javascript
function criarContador() {
    let contador = 0;

    return function() {
        contador++;
        return contador;
    };
}

const meuContador = criarContador();
console.log(meuContador());  // 1
console.log(meuContador());  // 2
console.log(meuContador());  // 3
```

## Callbacks

```javascript
function processar(numeros, callback) {
    return numeros.map(callback);
}

const dobrar = num => num * 2;
const resultado = processar([1, 2, 3], dobrar);
console.log(resultado);  // [2, 4, 6]

// Callback inline
const resultado2 = processar([1, 2, 3], num => num * 3);
console.log(resultado2);  // [3, 6, 9]
```

## Higher-Order Functions

### map
```javascript
const numeros = [1, 2, 3, 4, 5];
const dobrados = numeros.map(num => num * 2);
console.log(dobrados);  // [2, 4, 6, 8, 10]
```

### filter
```javascript
const numeros = [1, 2, 3, 4, 5, 6];
const pares = numeros.filter(num => num % 2 === 0);
console.log(pares);  // [2, 4, 6]
```

### reduce
```javascript
const numeros = [1, 2, 3, 4, 5];
const soma = numeros.reduce((total, num) => total + num, 0);
console.log(soma);  // 15
```

### forEach
```javascript
const frutas = [''maçã'', ''banana'', ''laranja''];
frutas.forEach(fruta => console.log(fruta));
```

### find
```javascript
const usuarios = [
    {id: 1, nome: ''João''},
    {id: 2, nome: ''Maria''},
    {id: 3, nome: ''Pedro''}
];

const usuario = usuarios.find(u => u.id === 2);
console.log(usuario);  // {id: 2, nome: "Maria"}
```

### some e every
```javascript
const numeros = [1, 2, 3, 4, 5];

// some: pelo menos um deve satisfazer
console.log(numeros.some(num => num > 3));  // true

// every: todos devem satisfazer
console.log(numeros.every(num => num > 0));  // true
console.log(numeros.every(num => num > 3));  // false
```

## IIFE (Immediately Invoked Function Expression)

```javascript
(function() {
    console.log(''Executada imediatamente!'');
})();

// Com arrow function
(() => {
    console.log(''Também funciona!'');
})();
```

## Recursão

```javascript
function fatorial(n) {
    if (n <= 1) return 1;
    return n * fatorial(n - 1);
}

console.log(fatorial(5));  // 120

// Fibonacci
function fibonacci(n) {
    if (n <= 1) return n;
    return fibonacci(n - 1) + fibonacci(n - 2);
}

console.log(fibonacci(7));  // 13
```

## Métodos de Array Avançados

### sort
```javascript
const numeros = [3, 1, 4, 1, 5, 9];
numeros.sort((a, b) => a - b);  // Crescente
console.log(numeros);  // [1, 1, 3, 4, 5, 9]

// Decrescente
numeros.sort((a, b) => b - a);
```

### slice
```javascript
const frutas = [''maçã'', ''banana'', ''laranja'', ''uva''];
const algumas = frutas.slice(1, 3);
console.log(algumas);  // [''banana'', ''laranja'']
```

### splice
```javascript
const frutas = [''maçã'', ''banana'', ''laranja''];
frutas.splice(1, 1, ''morango'');  // Remove 1 item no índice 1 e adiciona ''morango''
console.log(frutas);  // [''maçã'', ''morango'', ''laranja'']
```

## Exemplo Prático: Sistema de Tarefas

```javascript
const tarefas = [];

function adicionarTarefa(descricao) {
    const tarefa = {
        id: Date.now(),
        descricao,
        concluida: false
    };
    tarefas.push(tarefa);
    return tarefa;
}

function listarTarefas() {
    return tarefas;
}

function concluirTarefa(id) {
    const tarefa = tarefas.find(t => t.id === id);
    if (tarefa) {
        tarefa.concluida = true;
    }
}

function removerTarefa(id) {
    const indice = tarefas.findIndex(t => t.id === id);
    if (indice !== -1) {
        tarefas.splice(indice, 1);
    }
}

function tarefasPendentes() {
    return tarefas.filter(t => !t.concluida);
}

// Uso
adicionarTarefa(''Estudar JavaScript'');
adicionarTarefa(''Fazer exercícios'');
console.log(listarTarefas());
concluirTarefa(tarefas[0].id);
console.log(tarefasPendentes());
```

## Boas Práticas

1. **Use arrow functions** para callbacks curtos
2. **Funções pequenas**: Uma função, uma responsabilidade
3. **Nomes descritivos**: `calcularTotal()` em vez de `calc()`
4. **Evite muitos parâmetros**: Use objetos se necessário
5. **Pure functions**: Não modifique variáveis externas

