UPDATE lessons SET content = '# Arrays e Objetos em JavaScript

Arrays e objetos são as estruturas de dados mais importantes em JavaScript. Arrays armazenam listas ordenadas, enquanto objetos armazenam pares chave-valor.

## Arrays

### Criação
```javascript
// Array literal
const frutas = [''maçã'', ''banana'', ''laranja''];

// Array constructor
const numeros = new Array(1, 2, 3, 4, 5);

// Array vazio
const vazio = [];

// Array misto (não recomendado)
const misto = [1, ''texto'', true, {nome: ''João''}];
```

### Acesso
```javascript
const frutas = [''maçã'', ''banana'', ''laranja''];

console.log(frutas[0]);  // ''maçã''
console.log(frutas[1]);  // ''banana''
console.log(frutas[frutas.length - 1]);  // ''laranja'' (último)
```

### Modificação
```javascript
const frutas = [''maçã'', ''banana''];

// Adicionar no final
frutas.push(''laranja'');  // [''maçã'', ''banana'', ''laranja'']

// Adicionar no início
frutas.unshift(''morango'');  // [''morango'', ''maçã'', ''banana'', ''laranja'']

// Remover do final
const ultimo = frutas.pop();  // ''laranja''

// Remover do início
const primeiro = frutas.shift();  // ''morango''

// Modificar elemento
frutas[0] = ''uva'';
```

### Métodos Úteis
```javascript
const numeros = [1, 2, 3, 4, 5];

// length
console.log(numeros.length);  // 5

// includes
console.log(numeros.includes(3));  // true

// indexOf
console.log(numeros.indexOf(3));  // 2

// join
console.log(numeros.join('', ''));  // ''1, 2, 3, 4, 5''

// reverse
const invertido = numeros.reverse();  // [5, 4, 3, 2, 1]

// concat
const mais = numeros.concat([6, 7, 8]);  // [1, 2, 3, 4, 5, 6, 7, 8]
```

### Spread Operator
```javascript
const arr1 = [1, 2, 3];
const arr2 = [4, 5, 6];

// Combinar arrays
const combinado = [...arr1, ...arr2];  // [1, 2, 3, 4, 5, 6]

// Copiar array
const copia = [...arr1];

// Adicionar elementos
const novo = [0, ...arr1, 4];  // [0, 1, 2, 3, 4]
```

### Destructuring
```javascript
const frutas = [''maçã'', ''banana'', ''laranja''];

const [primeira, segunda] = frutas;
console.log(primeira);  // ''maçã''
console.log(segunda);  // ''banana''

// Pular elementos
const [, , terceira] = frutas;
console.log(terceira);  // ''laranja''

// Rest
const [primeira, ...resto] = frutas;
console.log(resto);  // [''banana'', ''laranja'']
```

## Objetos

### Criação
```javascript
// Object literal
const pessoa = {
    nome: ''João'',
    idade: 25,
    cidade: ''São Paulo''
};

// Object constructor
const pessoa2 = new Object();
pessoa2.nome = ''Maria'';
pessoa2.idade = 30;

// Objeto vazio
const vazio = {};
```

### Acesso
```javascript
const pessoa = {
    nome: ''João'',
    idade: 25,
    cidade: ''São Paulo''
};

// Dot notation
console.log(pessoa.nome);  // ''João''

// Bracket notation
console.log(pessoa[''idade'']);  // 25

// Propriedade dinâmica
const propriedade = ''cidade'';
console.log(pessoa[propriedade]);  // ''São Paulo''
```

### Modificação
```javascript
const pessoa = {
    nome: ''João'',
    idade: 25
};

// Adicionar propriedade
pessoa.cidade = ''São Paulo'';

// Modificar propriedade
pessoa.idade = 26;

// Deletar propriedade
delete pessoa.cidade;
```

### Métodos
```javascript
const pessoa = {
    nome: ''João'',
    idade: 25,
    saudacao: function() {
        return `Olá, meu nome é ${this.nome}`;
    },
    // Sintaxe curta (ES6)
    aniversario() {
        this.idade++;
    }
};

console.log(pessoa.saudacao());  // ''Olá, meu nome é João''
pessoa.aniversario();
console.log(pessoa.idade);  // 26
```

### Object Methods
```javascript
const pessoa = {
    nome: ''João'',
    idade: 25,
    cidade: ''SP''
};

// Object.keys
console.log(Object.keys(pessoa));  // [''nome'', ''idade'', ''cidade'']

// Object.values
console.log(Object.values(pessoa));  // [''João'', 25, ''SP'']

// Object.entries
console.log(Object.entries(pessoa));  
// [[''nome'', ''João''], [''idade'', 25], [''cidade'', ''SP'']]

// Object.assign (copiar/mesclar)
const copia = Object.assign({}, pessoa);
const mesclado = Object.assign({}, pessoa, {profissao: ''Dev''});
```

### Spread Operator
```javascript
const pessoa = {nome: ''João'', idade: 25};

// Copiar objeto
const copia = {...pessoa};

// Mesclar objetos
const completo = {...pessoa, cidade: ''SP'', profissao: ''Dev''};

// Sobrescrever propriedades
const atualizado = {...pessoa, idade: 26};
```

### Destructuring
```javascript
const pessoa = {
    nome: ''João'',
    idade: 25,
    cidade: ''SP''
};

// Básico
const {nome, idade} = pessoa;
console.log(nome);  // ''João''

// Renomear
const {nome: nomeCompleto} = pessoa;
console.log(nomeCompleto);  // ''João''

// Valor padrão
const {profissao = ''Desconhecido''} = pessoa;
console.log(profissao);  // ''Desconhecido''

// Rest
const {nome, ...resto} = pessoa;
console.log(resto);  // {idade: 25, cidade: ''SP''}
```

### Objetos Aninhados
```javascript
const usuario = {
    nome: ''João'',
    endereco: {
        rua: ''Av. Paulista'',
        numero: 1000,
        cidade: ''São Paulo''
    },
    hobbies: [''música'', ''esportes'']
};

console.log(usuario.endereco.cidade);  // ''São Paulo''
console.log(usuario.hobbies[0]);  // ''música''

// Destructuring aninhado
const {endereco: {cidade}} = usuario;
console.log(cidade);  // ''São Paulo''
```

### Optional Chaining (?.)
```javascript
const usuario = {
    nome: ''João'',
    endereco: {
        cidade: ''SP''
    }
};

// Sem optional chaining (pode dar erro)
// console.log(usuario.contato.telefone);  // ERRO!

// Com optional chaining
console.log(usuario.contato?.telefone);  // undefined (sem erro)
console.log(usuario.endereco?.cidade);  // ''SP''
```

### JSON

```javascript
// Objeto para JSON
const pessoa = {nome: ''João'', idade: 25};
const json = JSON.stringify(pessoa);
console.log(json);  // ''{"nome":"João","idade":25}''

// JSON para objeto
const jsonString = ''{"nome":"Maria","idade":30}'';
const objeto = JSON.parse(jsonString);
console.log(objeto.nome);  // ''Maria''
```

## Array de Objetos

```javascript
const usuarios = [
    {id: 1, nome: ''João'', idade: 25},
    {id: 2, nome: ''Maria'', idade: 30},
