function desativarProduto(id) {
    const produto = buscarProduto(id);
    if (produto) {
        produto.ativo = false;
    }
}

function calcularValorTotal() {
    return produtos
        .filter(p => p.ativo)
        .reduce((total, p) => total + (p.preco * p.estoque), 0);
}

